#nullable enable // autogenerated    

using System;
using System.Linq;
using MVZ2.GameContent.Buffs.Contraptions;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Grids;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Entities;
using PVZEngine.Grids;
using PVZEngine.Placements;

namespace MVZ2.GameContent.Placements
{
    public class FusionPlaceMethod : PlaceMethod
    {
        public override NamespaceID? GetPlaceError(PlacementDefinition placement, LawnGrid grid, EntityDefinition entity)
        {
            var fusionTargets = entity.GetFusionTargets();
            if (fusionTargets == null || fusionTargets.Length == 0)
            {
                return VanillaGridStatus.onlyUpgrade;
            }

            var entities = grid.GetEntities();
            if (entities.Count() <= 0 || !entities.Any(e => fusionTargets.Any(target => e.IsEntityOf(target)) && e.IsFriendlyEntity()))
            {
                return VanillaGridStatus.onlyUpgrade;
            }
            return null;
        }

        public override PlaceOutput PlaceEntity(PlacementDefinition placement, LawnGrid grid, EntityDefinition entityDef, PlaceParams param)
        {
            var fusionTargets = entityDef.GetFusionTargets();
            if (fusionTargets == null || fusionTargets.Length == 0)
                return PlaceOutput.InvalidOutput;

            var fusionResults = entityDef.GetFusionResults();
            var fusionResult = entityDef.GetFusionResult();

            // 쇱꿴角뤠賈痰寧寧뚤壇친駕  
            bool useMappingMode = fusionResults != null && fusionResults.Length > 0;

            var entity = grid.GetEntities().FirstOrDefault(e => fusionTargets.Any(target => e.IsEntityOf(target)) && e.IsFriendlyEntity());
            if (entity != null && entity.Exists())
            {
                NamespaceID targetResult;

                if (useMappingMode)
                {
                    // 寧寧뚤壇친駕：몽앴커깃茄竟瞳 fusionTargets 櫓돨乞多冷돕뚤壇돨 fusionResults  
                    var results = fusionResults ?? Array.Empty<NamespaceID>();
                    int targetIndex = Array.IndexOf(fusionTargets, entity.Definition.GetID());
                    if (targetIndex < 0 || targetIndex >= results.Length)
                        return PlaceOutput.InvalidOutput;
                    targetResult = results[targetIndex];
                }
                else
                {
                    // 뜩뚤寧친駕：賈痰데몸 fusionResult  
                    if (!NamespaceID.IsValid(fusionResult))
                        return PlaceOutput.InvalidOutput;
                    targetResult = fusionResult; // NamespaceID 角多痰잚謹，꼇矜狼 .Value  
                }

                bool isCommandBlock = param.IsCommandBlock();
                var ent = entity.UpgradeToContraption(targetResult);
                if (ent != null)
                {
                    if (isCommandBlock)
                    {
                        ent.AddBuff<ImitatedBuff>();
                    }
                    ent.SetVariant(param.GetVariant());
                }
                return new PlaceOutput(ent, entityDef)
                {
                    isCommandBlock = isCommandBlock,
                    increaseTakenConveyorSeed = true,
                };
            }
            return PlaceOutput.InvalidOutput;
        }
    }
}